if(!defined('ABSPATH'))exit;
final class TWJ_Neighborhood_Histories{
 const V='1.0.0',CAT='neighborhood-histories',CAT_NAME='Neighborhood Histories',PER_PAGE=24,MAP_MIN=5;
 function __construct(){
  add_action('init',array($this,'register'),5);add_action('init',array($this,'pattern'),20);add_action('wp_loaded',array($this,'provision'),50);add_action('rest_api_init',array($this,'rest'));
  add_shortcode('timewalk_neighborhood_histories',array($this,'directory'));add_shortcode('timewalk_neighborhood_quick_facts',array($this,'facts'));add_shortcode('timewalk_neighborhood_walk_section',array($this,'walk'));add_shortcode('timewalk_neighborhood_related_stories',array($this,'stories'));
  add_filter('post_type_link',array($this,'permalink'),20,2);add_filter('query_vars',array($this,'qvars'));add_filter('redirect_canonical',array($this,'canonical_redirect'),20,2);add_action('template_redirect',array($this,'redirects'));
  add_filter('the_content',array($this,'content_links'),22);add_action('astra_entry_header_before',array($this,'crumbs'));add_action('astra_entry_header_after',array($this,'subtitle'));
  add_filter('document_title_parts',array($this,'title'),30);add_filter('wp_robots',array($this,'robots'));add_action('wp_head',array($this,'head'),3);add_action('wp_enqueue_scripts',array($this,'assets'));
  add_filter('posts_search',array($this,'search'),20,2);add_action('save_post_post',array($this,'sync'),30,2);add_action('rest_after_insert_post',array($this,'sync_rest'),20,3);
 }
 function register(){
  $base=array('public'=>false,'publicly_queryable'=>false,'show_ui'=>true,'show_in_rest'=>true,'show_admin_column'=>true,'hierarchical'=>false,'rewrite'=>false,'query_var'=>false,'show_in_nav_menus'=>false);
  $tax=array('twj_nh_broad_area'=>array('Neighborhood Broad Areas','Neighborhood Broad Area'),'twj_nh_municipality'=>array('Neighborhood Municipalities','Neighborhood Municipality'),'twj_nh_character'=>array('Historical Characters','Historical Character'),'twj_nh_period'=>array('Neighborhood Historical Periods','Neighborhood Historical Period'),'twj_nh_station'=>array('Neighborhood Stations','Neighborhood Station'));
  foreach($tax as $slug=>$labels)register_taxonomy($slug,array('post'),array_merge($base,array('labels'=>array('name'=>$labels[0],'singular_name'=>$labels[1]))));
  $strings=array('_twj_neighborhood_history','_twj_nh_country','_twj_nh_prefecture','_twj_nh_city','_twj_nh_city_slug','_twj_nh_municipality','_twj_nh_broad_area','_twj_nh_area_en','_twj_nh_area_ja','_twj_nh_area_slug','_twj_nh_alternative_names','_twj_nh_nearest_stations','_twj_nh_historical_character','_twj_nh_main_periods','_twj_nh_short_description','_twj_nh_related_walk_url','_twj_nh_related_stories','_twj_nh_subtitle','_twj_nh_walk_available');
  foreach($strings as $k)register_post_meta('post',$k,array('type'=>'string','single'=>true,'show_in_rest'=>true,'sanitize_callback'=>'sanitize_text_field','auth_callback'=>array($this,'can_edit')));
  foreach(array('_twj_nh_latitude','_twj_nh_longitude') as $k)register_post_meta('post',$k,array('type'=>'number','single'=>true,'show_in_rest'=>true,'sanitize_callback'=>array($this,'number'),'auth_callback'=>array($this,'can_edit')));
  register_post_meta('post','_twj_nh_featured_priority',array('type'=>'integer','single'=>true,'show_in_rest'=>true,'sanitize_callback'=>'absint','auth_callback'=>array($this,'can_edit')));
  add_rewrite_tag('%twj_nh_city%','([a-z0-9-]+)');add_rewrite_rule('^([a-z0-9-]+)/([a-z0-9-]+-history)/?$','index.php?name=$matches[2]&twj_nh_city=$matches[1]','top');
 }
 function can_edit(){return current_user_can('edit_posts');}function number($v){return is_numeric($v)?(float)$v:0;}
 private function cat(){ $t=term_exists(self::CAT_NAME,'category');if(!$t)$t=wp_insert_term(self::CAT_NAME,'category',array('slug'=>self::CAT));if(is_wp_error($t))return 0;return is_array($t)?(int)$t['term_id']:(int)$t; }
 private function page($path){return get_page_by_path($path,OBJECT,'page');}private function url($path){$p=$this->page($path);return$p?get_permalink($p):home_url('/'.trim($path,'/').'/');}
 private function upsert($path,$title,$content,$parent,$seo,$desc){$p=$this->page($path);$a=array('post_type'=>'page','post_status'=>'publish','post_title'=>$title,'post_name'=>basename($path),'post_parent'=>(int)$parent,'post_content'=>$content,'comment_status'=>'closed','ping_status'=>'closed');if($p)$a['ID']=$p->ID;$id=$p?wp_update_post(wp_slash($a),true):wp_insert_post(wp_slash($a),true);if(is_wp_error($id)||!$id)return 0;foreach(array('_twj_neighborhood_hub'=>'1','_twj_seo_title'=>$seo,'_twj_meta_description'=>$desc,'_yoast_wpseo_title'=>$seo,'_yoast_wpseo_metadesc'=>$desc,'rank_math_title'=>$seo,'rank_math_description'=>$desc,'_yoast_wpseo_canonical'=>get_permalink($id),'rank_math_canonical_url'=>get_permalink($id))as$k=>$v)update_post_meta($id,$k,$v);return(int)$id;}
 private function national(){return '<!-- wp:paragraph {"className":"twj-nh-lead"} --><p class="twj-nh-lead">Japan’s neighborhoods are shaped by layers of geography, roads, rivers, temples, railways, industry, disaster, war and redevelopment. These local histories explain how today’s streets and districts came to look and feel the way they do—and where travelers can still see traces of the past.</p><!-- /wp:paragraph --><!-- wp:group {"className":"twj-nh-city-grid"} --><div class="wp-block-group twj-nh-city-grid"><!-- wp:group {"className":"twj-nh-city-card"} --><div class="wp-block-group twj-nh-city-card"><h2>Tokyo</h2><p>Explore how Tokyo’s neighborhoods grew from villages, post towns, temple quarters, railway suburbs, industrial zones and waterfront settlements.</p><p><a class="twj-nh-button" href="'.esc_url($this->url('tokyo/neighborhood-histories')).'">Explore Tokyo Neighborhood Histories</a></p></div><!-- /wp:group --></div><!-- /wp:group --><!-- wp:paragraph --><p>More cities will be added as the collection grows.</p><!-- /wp:paragraph -->';}
 private function tokyo(){return '<!-- wp:paragraph {"className":"twj-nh-lead"} --><p class="twj-nh-lead">Tokyo did not grow as a single planned city. Its neighborhoods developed from villages, post towns, temple districts, merchant quarters, military sites, railway suburbs, factory zones and reclaimed waterfronts. Explore how each area changed over time, why it developed its distinctive character, and what remains visible today.</p><!-- /wp:paragraph --><!-- wp:paragraph {"className":"twj-nh-note"} --><p class="twj-nh-note">These articles focus on historical neighborhoods rather than station boundaries. One history may therefore cover several nearby stations, while a major station area may contain more than one historically distinct neighborhood.</p><!-- /wp:paragraph --><!-- wp:shortcode -->[timewalk_neighborhood_histories city="tokyo"]<!-- /wp:shortcode -->';}
 function provision(){if(!$this->cat())return;$n=$this->page('neighborhood-histories');$tp=$this->page('tokyo');$t=$this->page('tokyo/neighborhood-histories');if((string)get_option('twj_nh_version','')===self::V&&$n&&$tp&&$t)return;$nid=$this->upsert('neighborhood-histories','Neighborhood Histories of Japan',$this->national(),0,'Neighborhood Histories of Japan | TimeWalk Japan','Explore the local histories of Japanese neighborhoods and discover how geography, roads, rivers, temples, railways, industry and redevelopment shaped the places travelers see today.');$tid=$this->upsert('tokyo/neighborhood-histories','Tokyo Neighborhood Histories',$this->tokyo(),$tp?(int)$tp->ID:0,'Tokyo Neighborhood Histories | TimeWalk Japan','Explore the histories of Tokyo neighborhoods, from old villages and post towns to railway suburbs, entertainment districts, industrial areas and modern city centers.');if($nid&&$tid){update_option('twj_nh_version',self::V,false);flush_rewrite_rules(false);}}
 function pattern(){if(!function_exists('register_block_pattern'))return;if(function_exists('register_block_pattern_category'))register_block_pattern_category('timewalk-japan',array('label'=>'TimeWalk Japan'));$c='<!-- wp:shortcode -->[timewalk_neighborhood_quick_facts]<!-- /wp:shortcode -->';foreach(array('Where Is This Neighborhood?'=>'Describe the historical neighborhood’s location, boundaries and relationship to nearby stations without treating station boundaries as the historical unit.','The Neighborhood Today'=>'Explain what travelers see and experience in the neighborhood today.','Geography and Early Settlement'=>'Explain the terrain, waterways, roads, villages, temples, shrines or other early foundations.','Historical Development'=>'Trace the neighborhood’s development chronologically using reliable sources.','Major Turning Points'=>'Identify the events, infrastructure, disasters, wars, industries or redevelopment projects that changed the area.','How the Past Shaped the Present'=>'Connect historical development to the present-day street pattern, land use, architecture and local character.','What You Can Still See Today'=>'List visible traces and explain what each one reveals about the neighborhood’s history.')as$h=>$p)$c.='<!-- wp:heading --><h2>'.$h.'</h2><!-- /wp:heading --><!-- wp:paragraph --><p>'.$p.'</p><!-- /wp:paragraph -->';$c.='<!-- wp:shortcode -->[timewalk_neighborhood_walk_section]<!-- /wp:shortcode --><!-- wp:shortcode -->[timewalk_neighborhood_related_stories]<!-- /wp:shortcode --><!-- wp:heading --><h2>Sources and Further Reading</h2><!-- /wp:heading --><!-- wp:list --><ul><li>Add municipal histories, museum publications, government records, academic works and other reliable sources.</li></ul><!-- /wp:list -->';register_block_pattern('timewalk-japan/neighborhood-history-article',array('title'=>'Neighborhood History Article','description'=>'Reusable structure for a TimeWalk Japan neighborhood history article.','categories'=>array('timewalk-japan'),'content'=>$c));}
 function rest(){register_rest_route('timewalk/v1','/neighborhood-status',array('methods'=>'GET','callback'=>array($this,'status'),'permission_callback'=>'__return_true'));}
 function status(){ $n=$this->page('neighborhood-histories');$t=$this->page('tokyo/neighborhood-histories');$tp=$this->page('tokyo');$s=$this->page('stories');$c=get_category_by_slug(self::CAT);return rest_ensure_response(array('module_version'=>self::V,'plugin_structure_ready'=>true,'national_page'=>$n?array('id'=>(int)$n->ID,'url'=>get_permalink($n),'status'=>$n->post_status):null,'tokyo_page'=>$t?array('id'=>(int)$t->ID,'url'=>get_permalink($t),'status'=>$t->post_status):null,'existing_tokyo_page_id'=>$tp?(int)$tp->ID:0,'existing_stories_page_id'=>$s?(int)$s->ID:0,'category'=>$c?array('id'=>(int)$c->term_id,'name'=>$c->name,'slug'=>$c->slug):null,'published_tokyo_neighborhood_histories'=>count($this->ids('tokyo')),'posts_per_page'=>self::PER_PAGE,'map_threshold'=>self::MAP_MIN,'taxonomies'=>array('twj_nh_broad_area','twj_nh_municipality','twj_nh_character','twj_nh_period','twj_nh_station')));}
 private function ispost($id){return$id&&get_post_type($id)==='post'&&((string)get_post_meta($id,'_twj_neighborhood_history',true)==='1'||has_category(self::CAT,$id));}private function city($id){$s=sanitize_title((string)get_post_meta($id,'_twj_nh_city_slug',true));if($s)return$s;$c=strtolower((string)get_post_meta($id,'_twj_nh_city',true));$p=strtolower((string)get_post_meta($id,'_twj_nh_prefecture',true));return($c==='tokyo'||strpos($p,'tokyo')!==false)?'tokyo':'';}
 function permalink($u,$p){if(!$p||!$this->ispost($p->ID)||!($c=$this->city($p->ID)))return$u;return home_url('/'.$c.'/'.$p->post_name.'/');}function qvars($v){$v[]='twj_nh_city';return$v;}function canonical_redirect($u,$r){return is_singular('post')&&$this->ispost(get_queried_object_id())?false:$u;}
 private function isnational(){if(!is_page())return false;$p=$this->page('neighborhood-histories');return$p&&(int)get_queried_object_id()===(int)$p->ID;}private function istokyo(){if(!is_page())return false;$p=$this->page('tokyo/neighborhood-histories');return$p&&(int)get_queried_object_id()===(int)$p->ID;}private function isdir(){return$this->isnational()||$this->istokyo();}
 function redirects(){if(is_category(self::CAT)){wp_safe_redirect($this->url('neighborhood-histories'),301);exit;}if(is_singular('post')&&$this->ispost(get_queried_object_id())){$asked=sanitize_title((string)get_query_var('twj_nh_city'));$expected=$this->city(get_queried_object_id());if($asked&&$expected&&$asked!==$expected){global$wp_query;$wp_query->set_404();status_header(404);nocache_headers();return;}remove_action('wp_head','rel_canonical');}if($this->isdir())remove_action('wp_head','rel_canonical');}
 function content_links($c){if(!in_the_loop()||!is_main_query())return$c;if(is_page('tokyo')){$u=esc_url($this->url('tokyo/neighborhood-histories'));$d='<p>Discover how Tokyo’s districts grew from villages, post towns, temple quarters, railway suburbs, industrial zones and waterfront settlements into the neighborhoods seen today.</p>';$b='<p><a class="twj-nh-button" href="'.$u.'">Explore Tokyo Neighborhood Histories</a></p>';$p='/<h2[^>]*>\s*Neighborhood Histories\s*<\/h2>\s*<p[^>]*>.*?<\/p>\s*<p[^>]*>\s*Coming soon\.?\s*<\/p>/is';$c=preg_match($p,$c)?preg_replace($p,'<h2>Neighborhood Histories</h2>'.$d.$b,$c,1):($c.(strpos($c,'Explore Tokyo Neighborhood Histories')===false?'<section class="twj-nh-context-card"><h2>Neighborhood Histories</h2>'.$d.$b.'</section>':''));}if(is_page('stories')&&strpos($c,'Explore Neighborhood Histories')===false){$l='<p><a class="twj-nh-text-link" href="'.esc_url($this->url('neighborhood-histories')).'">Explore Neighborhood Histories</a></p>';$p='/<h3[^>]*>\s*Cities and Neighborhoods\s*<\/h3>\s*<p[^>]*>.*?<\/p>/is';$c=preg_match($p,$c)?preg_replace($p,'$0'.$l,$c,1):$c.'<section class="twj-nh-context-card"><h2>Cities and Neighborhoods</h2><p>Explore how local geography, transport, industry and historical change shaped neighborhoods across Japan.</p>'.$l.'</section>';$x=$this->latest(3);if($x)$c.=$x;}if(is_front_page()&&strpos($c,'Latest Neighborhood Histories')===false&&$this->count()>=3){$x=$this->latest(3);if($x)$c.=$x;}return$c;}
 private function count(){return count($this->ids(''));}private function latest($n){$cat=get_category_by_slug(self::CAT);if(!$cat)return'';$q=new WP_Query(array('post_type'=>'post','post_status'=>'publish','posts_per_page'=>$n,'cat'=>(int)$cat->term_id,'orderby'=>'date','order'=>'DESC','no_found_rows'=>true));if(!$q->have_posts())return'';$h='<section class="twj-nh-latest"><h2>Latest Neighborhood Histories</h2><div class="twj-nh-mini-grid">';while($q->have_posts()){$q->the_post();$h.='<article><a href="'.esc_url(get_permalink()).'">'.esc_html(get_the_title()).'</a></article>';}wp_reset_postdata();return$h.'</div></section>';}
 function crumbs(){if(!is_singular('post')||!$this->ispost(get_queried_object_id()))return;$c=$this->city(get_queried_object_id());echo'<nav class="twj-nh-breadcrumbs" aria-label="Breadcrumb"><a href="'.esc_url(home_url('/')).'">Home</a><span>/</span><a href="'.esc_url($this->url('neighborhood-histories')).'">Neighborhood Histories</a><span>/</span><a href="'.esc_url($this->url($c.'/neighborhood-histories')).'">'.esc_html(ucwords(str_replace('-',' ',$c))).'</a><span>/</span><span aria-current="page">'.esc_html(get_the_title()).'</span></nav>';}
 function subtitle(){if(!is_singular('post')||!$this->ispost(get_queried_object_id()))return;$s=(string)get_post_meta(get_queried_object_id(),'_twj_nh_subtitle',true);if(!$s)$s=(string)get_post_meta(get_queried_object_id(),'_twj_nh_short_description',true);if($s)echo'<p class="twj-nh-single-lead">'.esc_html($s).'</p>';}
 private function termmeta($id,$tax,$key){$t=wp_get_post_terms($id,$tax,array('fields'=>'names'));return!is_wp_error($t)&&$t?implode(', ',$t):(string)get_post_meta($id,$key,true);}function facts(){if(!is_singular('post')||!$this->ispost(get_queried_object_id()))return'';$id=get_queried_object_id();$f=array('Japanese name'=>(string)get_post_meta($id,'_twj_nh_area_ja',true),'Ward or municipality'=>$this->termmeta($id,'twj_nh_municipality','_twj_nh_municipality'),'Nearest stations'=>(string)get_post_meta($id,'_twj_nh_nearest_stations',true),'Main historical periods'=>$this->termmeta($id,'twj_nh_period','_twj_nh_main_periods'),'Historical character'=>$this->termmeta($id,'twj_nh_character','_twj_nh_historical_character'));$h='';foreach($f as$k=>$v)if(trim($v)!=='')$h.='<dt>'.esc_html($k).'</dt><dd>'.esc_html($v).'</dd>';$w=(string)get_post_meta($id,'_twj_nh_related_walk_url',true);if($w)$h.='<dt>Related self-guided walk</dt><dd><a href="'.esc_url($w).'">Explore the walk</a></dd>';return$h?'<section class="twj-nh-quick-facts"><h2>Quick Facts</h2><dl>'.$h.'</dl></section>':'';}
 function walk(){if(!is_singular('post'))return'';$u=(string)get_post_meta(get_queried_object_id(),'_twj_nh_related_walk_url',true);return$u?'<section class="twj-nh-related-section"><h2>Walk This History</h2><p>Follow the related self-guided route to see this history in the streets.</p><p><a class="twj-nh-button" href="'.esc_url($u).'">Explore the walk</a></p></section>':'';}
 function stories(){if(!is_singular('post'))return'';$r=trim((string)get_post_meta(get_queried_object_id(),'_twj_nh_related_stories',true));if(!$r)return'';$h='';foreach(preg_split('/[\r\n,]+/',$r)as$x){$x=trim($x);if(!$x)continue;if(ctype_digit($x)&&($p=get_post((int)$x))&&$p->post_status==='publish')$h.='<li><a href="'.esc_url(get_permalink($p)).'">'.esc_html(get_the_title($p)).'</a></li>';elseif(filter_var($x,FILTER_VALIDATE_URL))$h.='<li><a href="'.esc_url($x).'">'.esc_html($x).'</a></li>';}return$h?'<section class="twj-nh-related-section"><h2>Related Stories</h2><ul>'.$h.'</ul></section>':'';}
 private function req($k){return isset($_GET[$k])?sanitize_text_field(wp_unslash($_GET[$k])):'';}private function ids($city){$c=get_category_by_slug(self::CAT);if(!$c)return array();$a=array('post_type'=>'post','post_status'=>'publish','posts_per_page'=>-1,'cat'=>(int)$c->term_id,'fields'=>'ids','no_found_rows'=>true);if($city){$a['meta_key']='_twj_nh_city_slug';$a['meta_value']=$city;}return get_posts($a);}
 private function options($tax,$ids,$sel,$label){$h='<option value="">'.esc_html($label).'</option>';if(!$ids)return$h;$t=get_terms(array('taxonomy'=>$tax,'hide_empty'=>true,'object_ids'=>$ids,'orderby'=>'name'));if(is_wp_error($t))return$h;foreach($t as$x)$h.='<option value="'.esc_attr($x->slug).'"'.selected($sel,$x->slug,false).'>'.esc_html($x->name).'</option>';return$h;}
 function directory($atts){$a=shortcode_atts(array('city'=>'tokyo'),$atts);$city=sanitize_title($a['city']);$k=$this->req('nh_search');$area=sanitize_title($this->req('nh_area'));$ward=sanitize_title($this->req('nh_ward'));$char=sanitize_title($this->req('nh_character'));$walk=$this->req('nh_walk');$page=max(1,absint($this->req('nh_page')));$cat=get_category_by_slug(self::CAT);$ids=$this->ids($city);$tax=array('relation'=>'AND');if($area)$tax[]=array('taxonomy'=>'twj_nh_broad_area','field'=>'slug','terms'=>$area);if($ward)$tax[]=array('taxonomy'=>'twj_nh_municipality','field'=>'slug','terms'=>$ward);if($char)$tax[]=array('taxonomy'=>'twj_nh_character','field'=>'slug','terms'=>$char);$meta=array('relation'=>'AND',array('key'=>'_twj_nh_city_slug','value'=>$city));if($walk==='yes')$meta[]=array('key'=>'_twj_nh_walk_available','value'=>'1');if($walk==='no')$meta[]=array('relation'=>'OR',array('key'=>'_twj_nh_walk_available','compare'=>'NOT EXISTS'),array('key'=>'_twj_nh_walk_available','value'=>'1','compare'=>'!='));$qargs=array('post_type'=>'post','post_status'=>'publish','posts_per_page'=>self::PER_PAGE,'paged'=>$page,'meta_key'=>'_twj_nh_featured_priority','orderby'=>array('meta_value_num'=>'DESC','date'=>'DESC','title'=>'ASC'),'meta_query'=>$meta,'twj_nh_directory'=>1,'twj_nh_keyword'=>$k);if($cat)$qargs['cat']=(int)$cat->term_id;if(count($tax)>1)$qargs['tax_query']=$tax;$q=new WP_Query($qargs);$action=get_permalink(get_queried_object_id());$h='<section class="twj-nh-directory"><form class="twj-nh-filters" method="get" action="'.esc_url($action).'"><label class="twj-nh-search"><span>Search</span><input type="search" name="nh_search" value="'.esc_attr($k).'" placeholder="Search by neighborhood, station or ward"></label><label><span>Area of Tokyo</span><select name="nh_area">'.$this->options('twj_nh_broad_area',$ids,$area,'All areas').'</select></label><label><span>Ward or municipality</span><select name="nh_ward">'.$this->options('twj_nh_municipality',$ids,$ward,'All wards and municipalities').'</select></label><label><span>Historical character</span><select name="nh_character">'.$this->options('twj_nh_character',$ids,$char,'All historical characters').'</select></label><label><span>Self-guided walk available</span><select name="nh_walk"><option value="">Either</option><option value="yes"'.selected($walk,'yes',false).'>Yes</option><option value="no"'.selected($walk,'no',false).'>No</option></select></label><div class="twj-nh-filter-actions"><button type="submit">Apply filters</button>'.(($k||$area||$ward||$char||$walk)?'<a href="'.esc_url($action).'">Clear</a>':'').'</div></form>';
  if(!$ids)$h.='<div class="twj-nh-empty"><p>Neighborhood histories are now being prepared. New articles will appear here as they are published.</p><div><a class="twj-nh-button" href="'.esc_url($this->url('stories')).'">Explore Tokyo Stories</a><a class="twj-nh-button twj-nh-button--secondary" href="'.esc_url($this->url('self-guided-walks')).'">Browse Self-Guided Walks</a></div></div>';elseif(!$q->have_posts())$h.='<div class="twj-nh-empty"><p>No neighborhood histories match your search or filters.</p><p><a href="'.esc_url($action).'">Clear the filters</a></p></div>';else{$h.='<p class="twj-nh-result-count">'.esc_html(number_format_i18n($q->found_posts)).' neighborhood histories</p><div class="twj-nh-grid">';while($q->have_posts()){$q->the_post();$h.=$this->card(get_the_ID());}$h.='</div>'.$this->pages($q,$page,$action);}wp_reset_postdata();$m=$this->map($ids);if($m)$h.=$m;return$h.'<section class="twj-nh-explore-more"><h2>Keep Exploring</h2><p><a href="'.esc_url($this->url('stories')).'">Explore Tokyo Stories</a> · <a href="'.esc_url($this->url('self-guided-walks')).'">Browse Self-Guided Walks</a></p></section></section>';}
 function search($s,$q){if(!$q->get('twj_nh_directory')||!($k=trim((string)$q->get('twj_nh_keyword'))))return$s;global$wpdb;$like='%'.$wpdb->esc_like($k).'%';$keys=array('_twj_nh_area_en','_twj_nh_area_ja','_twj_nh_alternative_names','_twj_nh_nearest_stations','_twj_nh_municipality','_twj_nh_short_description');$ph=implode(',',array_fill(0,count($keys),'%s'));$params=array_merge(array($like,$like,$like),$keys,array($like));return$wpdb->prepare(" AND (({$wpdb->posts}.post_title LIKE %s) OR ({$wpdb->posts}.post_excerpt LIKE %s) OR ({$wpdb->posts}.post_content LIKE %s) OR EXISTS (SELECT 1 FROM {$wpdb->postmeta} pm WHERE pm.post_id={$wpdb->posts}.ID AND pm.meta_key IN ($ph) AND pm.meta_value LIKE %s)) ",$params);}
 private function card($id){$t=(string)get_post_meta($id,'_twj_nh_area_en',true);if(!$t)$t=get_the_title($id);$ja=(string)get_post_meta($id,'_twj_nh_area_ja',true);$mun=$this->termmeta($id,'twj_nh_municipality','_twj_nh_municipality');$st=(string)get_post_meta($id,'_twj_nh_nearest_stations',true);$d=(string)get_post_meta($id,'_twj_nh_short_description',true);if(!$d)$d=get_the_excerpt($id);$terms=wp_get_post_terms($id,'twj_nh_character');$w=(string)get_post_meta($id,'_twj_nh_related_walk_url',true);$u=get_permalink($id);$img=has_post_thumbnail($id)?get_the_post_thumbnail($id,'medium_large',array('loading'=>'lazy','decoding'=>'async','alt'=>trim($t.' neighborhood history'))):'';$h='<article class="twj-nh-card">'.($img?'<a class="twj-nh-card__image" href="'.esc_url($u).'">'.$img.'</a>':'').'<div class="twj-nh-card__body"><h2><a href="'.esc_url($u).'">'.esc_html($t).'</a></h2>';$m=trim($ja.($ja&&$mun?' · ':'').$mun);if($m)$h.='<p class="twj-nh-card__meta">'.esc_html($m).'</p>';if($st)$h.='<p class="twj-nh-card__stations">Near '.esc_html($st).'</p>';if($d)$h.='<p class="twj-nh-card__description">'.esc_html($d).'</p>';if(!is_wp_error($terms)&&$terms){$h.='<ul class="twj-nh-tags">';foreach(array_slice($terms,0,4)as$x)$h.='<li>'.esc_html($x->name).'</li>';$h.='</ul>';}$h.='<div class="twj-nh-card__actions"><a class="twj-nh-button" href="'.esc_url($u).'">Read the history</a>'.($w?'<a class="twj-nh-button twj-nh-button--secondary" href="'.esc_url($w).'">Explore the walk</a>':'').'</div></div></article>';return$h;}
 private function pages($q,$cur,$action){if((int)$q->max_num_pages<2)return'';$a=array();foreach(array('nh_search','nh_area','nh_ward','nh_character','nh_walk')as$k)if(($v=$this->req($k))!=='')$a[$k]=$v;$base=add_query_arg(array_merge($a,array('nh_page'=>'%#%')),$action);$l=paginate_links(array('base'=>$base,'format'=>'','current'=>$cur,'total'=>(int)$q->max_num_pages,'type'=>'list','prev_text'=>'Previous','next_text'=>'Next'));return$l?'<nav class="twj-nh-pagination" aria-label="Neighborhood history pages">'.$l.'</nav>':'';}
 private function map($ids){$p=array();foreach($ids as$id){$lat=get_post_meta($id,'_twj_nh_latitude',true);$lng=get_post_meta($id,'_twj_nh_longitude',true);if(is_numeric($lat)&&is_numeric($lng))$p[]=array('lat'=>(float)$lat,'lng'=>(float)$lng,'name'=>(string)(get_post_meta($id,'_twj_nh_area_en',true)?:get_the_title($id)),'url'=>get_permalink($id));}return count($p)<self::MAP_MIN?'':'<section class="twj-nh-map-section"><h2>Explore Neighborhood Histories on the Map</h2><p>The map is an additional way to browse. Every article remains available through search, filters and the directory.</p><details class="twj-nh-map-details"><summary>Open the map</summary><div class="twj-nh-map" data-points="'.esc_attr(wp_json_encode($p)).'"></div></details></section>';}
 function title($p){if($this->isnational())$p['title']='Neighborhood Histories of Japan | TimeWalk Japan';if($this->istokyo())$p['title']='Tokyo Neighborhood Histories | TimeWalk Japan';return$p;}function robots($r){if($this->isdir()&&(isset($_GET['nh_search'])||isset($_GET['nh_area'])||isset($_GET['nh_ward'])||isset($_GET['nh_character'])||isset($_GET['nh_walk'])||isset($_GET['nh_page']))){$r['noindex']=true;$r['follow']=true;unset($r['index']);}return$r;}
 function head(){$d=$u='';if($this->isnational()){$d='Explore the local histories of Japanese neighborhoods and discover how geography, roads, rivers, temples, railways, industry and redevelopment shaped the places travelers see today.';$u=$this->url('neighborhood-histories');}elseif($this->istokyo()){$d='Explore the histories of Tokyo neighborhoods, from old villages and post towns to railway suburbs, entertainment districts, industrial areas and modern city centers.';$u=$this->url('tokyo/neighborhood-histories');}elseif(is_singular('post')&&$this->ispost(get_queried_object_id())){$d=(string)get_post_meta(get_queried_object_id(),'_twj_nh_short_description',true);if(!$d)$d=get_the_excerpt(get_queried_object_id());$u=get_permalink(get_queried_object_id());}if($d)echo'<meta name="description" content="'.esc_attr($d).'">';if($u)echo'<link rel="canonical" href="'.esc_url($u).'">';$s=$this->schema();if($s)echo'<script type="application/ld+json">'.wp_json_encode($s,JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE).'</script>';}
 private function bc($a){$e=array();$i=1;foreach($a as$n=>$u)$e[]=array('@type'=>'ListItem','position'=>$i++,'name'=>$n,'item'=>$u);return array('@type'=>'BreadcrumbList','itemListElement'=>$e);}private function schema(){if($this->isnational())return array('@context'=>'https://schema.org','@graph'=>array($this->bc(array('Home'=>home_url('/'),'Neighborhood Histories'=>$this->url('neighborhood-histories'))),array('@type'=>'ItemList','name'=>'Neighborhood Histories of Japan','numberOfItems'=>1,'itemListElement'=>array(array('@type'=>'ListItem','position'=>1,'name'=>'Tokyo Neighborhood Histories','url'=>$this->url('tokyo/neighborhood-histories'))))));if($this->istokyo()){$e=array();$i=1;foreach(array_slice($this->ids('tokyo'),0,self::PER_PAGE)as$id)$e[]=array('@type'=>'ListItem','position'=>$i++,'name'=>get_the_title($id),'url'=>get_permalink($id));return array('@context'=>'https://schema.org','@graph'=>array($this->bc(array('Home'=>home_url('/'),'Neighborhood Histories'=>$this->url('neighborhood-histories'),'Tokyo'=>$this->url('tokyo/neighborhood-histories'))),array('@type'=>'ItemList','name'=>'Tokyo Neighborhood Histories','numberOfItems'=>count($e),'itemListElement'=>$e)));}if(is_singular('post')&&$this->ispost(get_queried_object_id())){$id=get_queried_object_id();$c=$this->city($id);$a=array('@type'=>'Article','headline'=>get_the_title($id),'url'=>get_permalink($id),'mainEntityOfPage'=>get_permalink($id),'datePublished'=>get_the_date('c',$id),'dateModified'=>get_the_modified_date('c',$id),'description'=>(string)(get_post_meta($id,'_twj_nh_short_description',true)?:get_the_excerpt($id)),'author'=>array('@type'=>'Organization','name'=>'TimeWalk Japan'),'publisher'=>array('@type'=>'Organization','name'=>'TimeWalk Japan'));if(has_post_thumbnail($id))$a['image']=array(wp_get_attachment_image_url(get_post_thumbnail_id($id),'full'));return array('@context'=>'https://schema.org','@graph'=>array($this->bc(array('Home'=>home_url('/'),'Neighborhood Histories'=>$this->url('neighborhood-histories'),ucwords($c)=>$this->url($c.'/neighborhood-histories'),get_the_title($id)=>get_permalink($id))),$a));}return null;}
 function assets(){$ok=$this->isdir()||is_page('tokyo')||is_page('stories')||is_front_page()||(is_singular('post')&&$this->ispost(get_queried_object_id()));if(!$ok)return;$base=plugin_dir_url(dirname(__FILE__));wp_enqueue_style('twj-neighborhood-histories',$base.'assets/timewalk-neighborhood-histories.css',array(),self::V);wp_enqueue_script('twj-neighborhood-histories',$base.'assets/timewalk-neighborhood-histories.js',array(),self::V,true);}
 function sync_rest($p,$r,$c){if($p&&$p->post_type==='post')$this->sync($p->ID,$p);}function sync($id,$p){if(!$p||$p->post_type!=='post'||wp_is_post_revision($id)||!$this->ispost($id))return;update_post_meta($id,'_twj_neighborhood_history','1');if(get_post_meta($id,'_twj_nh_featured_priority',true)==='')update_post_meta($id,'_twj_nh_featured_priority',0);foreach(array('twj_nh_broad_area'=>'_twj_nh_broad_area','twj_nh_municipality'=>'_twj_nh_municipality','twj_nh_character'=>'_twj_nh_historical_character','twj_nh_period'=>'_twj_nh_main_periods','twj_nh_station'=>'_twj_nh_nearest_stations')as$t=>$k){$r=trim((string)get_post_meta($id,$k,true));if($r)wp_set_object_terms($id,array_filter(array_map('trim',preg_split('/[\r\n,]+/',$r))),$t,false);}if(get_post_meta($id,'_twj_nh_related_walk_url',true))update_post_meta($id,'_twj_nh_walk_available','1');}
